mapper.select:


    del_flag = '0'
     and task_id = #{taskId}
     and bid_id = #{bidId}
     and outline_id = #{outlineId}
     and content_id = #{contentId}
     and issue_type = #{issueType}
     and severity = #{severity}
     and status = #{status}

order by severity desc, outline_id asc, content_id asc, id asc
